mapper.select:
select o.id, o.order_no, o.user_id, o.companion_id, cp.name as companion_name, u.phone as companion_phone, cp.avatar as companion_avatar, o.service_id, o.service_name, o.service_image, o.patient_id, p.name as patient_name, o.hospital, o.department, o.appointment_time, o.pickup_option, o.pickup_address, o.remarks, o.amount, o.actual_amount, o.pay_method, o.pay_time, o.status, o.refund_reason, o.refund_time, o.complete_time, o.create_time, o.update_time, CASE WHEN orv.id IS NOT NULL THEN true ELSE false END as reviewed, orv.score as reviewScore, orv.content as reviewContent from orders o left join companion_profile cp on o.companion_id = cp.id left join sys_user u on cp.user_id = u.id left join patient p on o.patient_id = p.id left join order_review orv on o.id = orv.order_id where o.user_id = #{userId}
and o.status = #{status}
order by o.create_time desc limit #{offset}, #{pageSize}

select count(*) from orders
where user_id = #{userId}

    and status = #{status}

select * from orders
where companion_id = #{companionId}
and DATE(appointment_time) = #{date}
and status in (1, 2, 7, 3)

mapper.insert:
insert into order_review (
    order_id, user_id, companion_id, user_name, user_avatar, score, content, images, time
) values (
    #{orderId}, #{userId}, #{companionId}, #{userName}, #{userAvatar},
    #{score}, #{content}, #{images}, now()
)
